const STORAGE_KEYS = {
    cache: 'reembolso_viagens_cache_v3'
};
const API_ENDPOINT = '/.netlify/functions/reembolso-api';
const REQUEST_TIMEOUT_MS = 30000;
const AUTO_SYNC_INTERVAL_MS = 5000;
const MAX_ATTACHMENT_SIZE_BYTES = 2 * 1024 * 1024;
const MAX_ATTACHMENTS_TOTAL_BYTES = 4.5 * 1024 * 1024;
let syncInterval = null;
let syncInFlight = false;

function generateId(prefix = 'id_') {
    const suffix = (window.crypto && typeof window.crypto.randomUUID === 'function')
        ? window.crypto.randomUUID()
        : `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
    return `${prefix}${suffix}`;
}

function ordenarColecoes() {
    colaboradores = [...colaboradores].sort((a, b) => (a.nome || '').localeCompare(b.nome || '', 'pt-BR'));
    obras = [...obras].sort((a, b) => (a.nome || '').localeCompare(b.nome || '', 'pt-BR'));
    lancamentos = [...lancamentos].sort((a, b) => {
        const da = new Date(b.criadoEm || b.updatedAt || 0).getTime();
        const db = new Date(a.criadoEm || a.updatedAt || 0).getTime();
        return da - db;
    });
}

function sanitizeAttachmentForCache(anexo) {
    if (!anexo || typeof anexo !== 'object') return anexo;
    const { dataUrl, ...rest } = anexo;
    return rest;
}

function sanitizeLancamentoForCache(lancamento) {
    if (!lancamento || typeof lancamento !== 'object') return lancamento;
    return {
        ...lancamento,
        anexos: Array.isArray(lancamento.anexos) ? lancamento.anexos.map(sanitizeAttachmentForCache) : [],
        kmDetalhes: Array.isArray(lancamento.kmDetalhes) ? lancamento.kmDetalhes.map(item => ({
            ...item,
            anexos: Array.isArray(item?.anexos) ? item.anexos.map(sanitizeAttachmentForCache) : []
        })) : [],
        refeicoesDetalhes: Array.isArray(lancamento.refeicoesDetalhes) ? lancamento.refeicoesDetalhes.map(item => ({
            ...item,
            anexos: Array.isArray(item?.anexos) ? item.anexos.map(sanitizeAttachmentForCache) : []
        })) : [],
        outrosDetalhes: Array.isArray(lancamento.outrosDetalhes) ? lancamento.outrosDetalhes.map(item => ({
            ...item,
            anexos: Array.isArray(item?.anexos) ? item.anexos.map(sanitizeAttachmentForCache) : []
        })) : []
    };
}

function obterSnapshotDados(options = {}) {
    const { forCache = false } = options;
    return {
        colaboradores,
        obras,
        lancamentos: forCache ? lancamentos.map(sanitizeLancamentoForCache) : lancamentos,
        parametros
    };
}

function salvarCacheLocal() {
    try {
        localStorage.setItem(STORAGE_KEYS.cache, JSON.stringify(obterSnapshotDados({ forCache: true })));
    } catch (error) {
        console.warn('Não foi possível atualizar o cache local.', error);
    }
}

function carregarCacheLocal() {
    try {
        const cache = JSON.parse(localStorage.getItem(STORAGE_KEYS.cache));
        if (!cache || typeof cache !== 'object') return;
        if (Array.isArray(cache.colaboradores) && cache.colaboradores.length) colaboradores = cache.colaboradores;
        if (Array.isArray(cache.obras) && cache.obras.length) obras = cache.obras;
        if (Array.isArray(cache.lancamentos)) lancamentos = cache.lancamentos;
        if (cache.parametros && typeof cache.parametros === 'object') {
            parametros = { ...parametros, ...cache.parametros };
        }
        ordenarColecoes();
    } catch (error) {
        console.warn('Não foi possível ler o cache local.', error);
    }
}

async function apiRequest(action, payload = {}) {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);

    try {
        const response = await fetch(API_ENDPOINT, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action, ...payload }),
            signal: controller.signal
        });

        const data = await response.json().catch(() => ({}));
        if (!response.ok || data.ok === false) {
            throw new Error(data.error || 'Falha de comunicação com a persistência remota.');
        }
        return data;
    } catch (error) {
        if (error?.name === 'AbortError') {
            throw new Error('Tempo de resposta excedido ao acessar a persistência compartilhada.');
        }
        throw error;
    } finally {
        clearTimeout(timeout);
    }
}

function aplicarDadosRemotos(data = {}) {
    colaboradores = Array.isArray(data.colaboradores) ? data.colaboradores : colaboradores;
    obras = Array.isArray(data.obras) ? data.obras : obras;
    lancamentos = Array.isArray(data.lancamentos) ? data.lancamentos : lancamentos;
    if (data.parametros && typeof data.parametros === 'object') {
        parametros = { ...parametros, ...data.parametros };
    }
    ordenarColecoes();
    salvarCacheLocal();
}

async function carregarDadosLocais() {
    carregarCacheLocal();

    try {
        const remoto = await apiRequest('bootstrap');
        const data = remoto.data || {};
        const remotoVazio = !data.colaboradores?.length && !data.obras?.length && !data.lancamentos?.length && !data.parametros;

        if (remotoVazio) {
            const inicializado = await apiRequest('initializeIfEmpty', { data: obterSnapshotDados() });
            aplicarDadosRemotos(inicializado.data || {});
            return;
        }

        aplicarDadosRemotos(data);
    } catch (error) {
        console.warn('Persistência remota indisponível. Mantendo cache local.', error);
    }
}

async function sincronizarDadosSilenciosamente() {
    if (syncInFlight) return;
    try {
        syncInFlight = true;
        const remoto = await apiRequest('bootstrap');
        aplicarDadosRemotos(remoto.data || {});
        popularSelects();
        atualizarDashboard();
        renderColaboradores();
        renderObras();
        renderAprovacoes();
        filtrarRelatorio();
        renderPainelMestre();
    } catch (error) {
        console.warn('Falha na sincronização silenciosa.', error);
    } finally {
        syncInFlight = false;
    }
}

function iniciarSincronizacaoAutomatica() {
    if (syncInterval) clearInterval(syncInterval);
    syncInterval = setInterval(sincronizarDadosSilenciosamente, AUTO_SYNC_INTERVAL_MS);
}

function atualizarDataTopo() {
    const el = document.getElementById('topbar-date');
    if (!el) return;
    const now = new Date();
    el.textContent = now.toLocaleDateString('pt-BR', {
        weekday: 'long',
        day: 'numeric',
        month: 'long'
    });
}

function iniciarAtualizacaoAutomaticaData() {
    atualizarDataTopo();
    if (window.dateRefreshInterval) clearInterval(window.dateRefreshInterval);
    window.dateRefreshInterval = setInterval(atualizarDataTopo, 60000);
}

function configurePdfJs() {
    if (window.pdfjsLib) {
        window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/2.16.105/pdf.worker.min.js';
    }
}

function navigate(page) {
    document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    document.getElementById('page-' + page).classList.add('active');
    document.querySelector(`[data-page="${page}"]`).classList.add('active');
    const pageTitleMap = { 'painel-mestre': 'Visão Geral' };
    document.getElementById('topbar-title').textContent = pageTitleMap[page] || (page.charAt(0).toUpperCase() + page.slice(1).replace('-', ' '));

    if (page === 'dashboard') atualizarDashboard();
    if (page === 'colaboradores') renderColaboradores();
    if (page === 'obras') renderObras();
    if (page === 'aprovacoes') renderAprovacoes();
    if (page === 'relatorios') {
        popularSelects();
        filtrarRelatorio();
    }
    if (page === 'painel-mestre') renderPainelMestre();
}

function showToast(msg) {
    const c = document.getElementById('toast-container');
    const t = document.createElement('div');
    t.className = 'toast';
    t.innerHTML = `<i class="fas fa-check-circle"></i> ${msg}`;
    c.appendChild(t);
    setTimeout(() => t.remove(), 3000);
}

