function calcRefRow(idx) {
    const dS = document.querySelector(`#ref-row-${idx} .ref-d-saida`).value;
    const hS = document.querySelector(`#ref-row-${idx} .ref-h-saida`).value;
    const dC = document.querySelector(`#ref-row-${idx} .ref-d-chegada`).value;
    const hC = document.querySelector(`#ref-row-${idx} .ref-h-chegada`).value;
    if (!dS || !dC) return;
    const start = new Date(`${dS}T${hS}`);
    const end = new Date(`${dC}T${hC}`);
    if (end < start) return;
    const list = document.getElementById(`ref-list-${idx}`);
    list.style.display = 'block';
    let html = '';
    const current = new Date(start);
    current.setHours(0, 0, 0, 0);
    const finish = new Date(end);
    finish.setHours(23, 59, 59, 999);
    while (current <= finish) {
        const dStr = current.toISOString().split('T')[0];
        html += `<div class="ref-day"><div class="ref-day-title">${dStr.split('-').reverse().join('/')}</div><div class="ref-items">`;
        const cafeH = parametros.cafeInicio.split(':');
        const cafeF = parametros.cafeFim.split(':');
        const almocoH = parametros.almocoInicio.split(':');
        const almocoF = parametros.almocoFim.split(':');
        const jantarH = parametros.jantarInicio.split(':');
        const jantarF = parametros.jantarFim.split(':');
        const meals = [{
            t: 'Café',
            hs: parseInt(cafeH[0]),
            ms: parseInt(cafeH[1]),
            he: parseInt(cafeF[0]),
            me: parseInt(cafeF[1]),
            p: parametros.cafe
        }, {
            t: 'Almoço',
            hs: parseInt(almocoH[0]),
            ms: parseInt(almocoH[1]),
            he: parseInt(almocoF[0]),
            me: parseInt(almocoF[1]),
            p: parametros.almoco
        }, {
            t: 'Jantar',
            hs: parseInt(jantarH[0]),
            ms: parseInt(jantarH[1]),
            he: parseInt(jantarF[0]),
            me: parseInt(jantarF[1]),
            p: parametros.jantar
        }];
        meals.forEach(m => {
            const mS = new Date(current);
            mS.setHours(m.hs, m.ms, 0);
            const mE = new Date(current);
            mE.setHours(m.he, m.me, 0);
            if (start <= mE && end >= mS) {
                const key = `${dStr}_${m.t}`;
                const isEx = (refeicoesExcluidas[idx] || []).includes(key);
                html += `<div class="ref-item ${isEx ? 'excluded' : ''}"><span>${m.t} (R$ ${m.p.toFixed(2)})</span><button type="button" class="ref-exclude-btn" onclick="toggleRef(${idx},'${dStr}','${m.t}')"><i class="fas ${isEx ? 'fa-undo' : 'fa-trash'}"></i></button></div>`;
            }
        });
        html += `</div></div>`;
        current.setDate(current.getDate() + 1);
    }
    list.innerHTML = html;
    atualizarTotais();
}

function toggleRef(idx, date, type) {
    const key = `${date}_${type}`;
    if (!refeicoesExcluidas[idx]) refeicoesExcluidas[idx] = [];
    if (refeicoesExcluidas[idx].includes(key)) {
        refeicoesExcluidas[idx] = refeicoesExcluidas[idx].filter(k => k !== key);
    } else {
        refeicoesExcluidas[idx].push(key);
    }
    calcRefRow(idx);
}

function atualizarTotais() {
    let km = 0;
    document.querySelectorAll('.km-day-row').forEach(r => {
        km += (parseFloat(r.querySelector('.km-ida').value) || 0) + (parseFloat(r.querySelector('.km-volta').value) || 0);
    });
    const vComb = km * parametros.vlrKm;
    document.getElementById('unif-total-km').textContent = km.toFixed(1);
    document.getElementById('unif-total-comb').textContent = formatMoeda(vComb);

    let ref = 0;
    document.querySelectorAll('.ref-day-row').forEach(r => {
        const idx = r.id.split('-')[2];
        const dS = r.querySelector('.ref-d-saida').value;
        const hS = r.querySelector('.ref-h-saida').value;
        const dC = r.querySelector('.ref-d-chegada').value;
        const hC = r.querySelector('.ref-h-chegada').value;
        if (dS && dC) {
            const start = new Date(`${dS}T${hS}`);
            const end = new Date(`${dC}T${hC}`);
            const cur = new Date(start);
            cur.setHours(0, 0, 0, 0);
            const fin = new Date(end);
            fin.setHours(23, 59, 59, 999);
            while (cur <= fin) {
                const dStr = cur.toISOString().split('T')[0];
                [{
                    t: 'Café',
                    hs: parseInt(parametros.cafeInicio.split(':')[0]),
                    ms: parseInt(parametros.cafeInicio.split(':')[1]),
                    he: parseInt(parametros.cafeFim.split(':')[0]),
                    me: parseInt(parametros.cafeFim.split(':')[1]),
                    p: parametros.cafe
                }, {
                    t: 'Almoço',
                    hs: parseInt(parametros.almocoInicio.split(':')[0]),
                    ms: parseInt(parametros.almocoInicio.split(':')[1]),
                    he: parseInt(parametros.almocoFim.split(':')[0]),
                    me: parseInt(parametros.almocoFim.split(':')[1]),
                    p: parametros.almoco
                }, {
                    t: 'Jantar',
                    hs: parseInt(parametros.jantarInicio.split(':')[0]),
                    ms: parseInt(parametros.jantarInicio.split(':')[1]),
                    he: parseInt(parametros.jantarFim.split(':')[0]),
                    me: parseInt(parametros.jantarFim.split(':')[1]),
                    p: parametros.jantar
                }].forEach(m => {
                    const mS = new Date(cur);
                    mS.setHours(m.hs, m.ms, 0);
                    const mE = new Date(cur);
                    mE.setHours(m.he, m.me, 0);
                    if (start <= mE && end >= mS && !(refeicoesExcluidas[idx] || []).includes(`${dStr}_${m.t}`)) {
                        ref += m.p;
                    }
                });
                cur.setDate(cur.getDate() + 1);
            }
        }
    });
    document.getElementById('unif-total-ref').textContent = formatMoeda(ref);

    let out = 0;
    document.querySelectorAll('.out-vlr').forEach(i => {
        out += (parseFloat(i.value) || 0);
    });
    document.getElementById('unif-total-outros').textContent = formatMoeda(out);
    document.getElementById('unif-total-geral').textContent = formatMoeda(vComb + ref + out);

    const dates = [];
    document.querySelectorAll('input[type="date"]').forEach(i => {
        if (i.value) dates.push(i.value);
    });
    if (dates.length) {
        dates.sort();
        document.getElementById('unif-periodo').value = dates[0].split('-').reverse().join('/') + ' a ' + dates[dates.length - 1].split('-').reverse().join('/');
    } else {
        document.getElementById('unif-periodo').value = '';
    }
}

function formatMoeda(v) {
    return 'R$ ' + (v || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function extrairValorMoeda(texto) {
    return parseFloat((texto || '0').replace('R$ ', '').replace(/\./g, '').replace(',', '.')) || 0;
}

function formatDateBR(dateStr) {
    if (!dateStr) return '-';
    const parts = dateStr.split('-');
    if (parts.length !== 3) return dateStr;
    return `${parts[2]}/${parts[1]}/${parts[0]}`;
}

function formatBytes(bytes) {
    if (!bytes && bytes !== 0) return '-';
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(2)} MB`;
}

function escapeHtml(value) {
    return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function getFileKind(fileName = '', mimeType = '') {
    const name = fileName.toLowerCase();
    const type = (mimeType || '').toLowerCase();
    if (type.includes('pdf') || name.endsWith('.pdf')) return 'pdf';
    if (type.startsWith('image/') || /\.(png|jpg|jpeg|webp)$/i.test(name)) return 'image';
    return 'other';
}

function fileToDataURL(file) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = e => resolve(e.target.result);
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

async function buildAttachmentRecords(files, meta = {}) {
    const list = [];
    for (const file of Array.from(files || [])) {
        if ((file.size || 0) > MAX_ATTACHMENT_SIZE_BYTES) {
            throw new Error(`O arquivo ${file.name} excede o limite de 2 MB por anexo.`);
        }
        const dataUrl = await fileToDataURL(file);
        list.push({
            id: generateId('anx_'),
            nome: file.name,
            tipo: file.type || '',
            tamanho: file.size || 0,
            kind: getFileKind(file.name, file.type),
            dataUrl,
            categoria: meta.categoria || 'Anexo',
            origem: meta.origem || ''
        });
    }
    return list;
}

function getMealItemsFromRow(row, idx) {
    const itens = [];
    row.querySelectorAll(`#ref-list-${idx} .ref-item:not(.excluded) span`).forEach(span => {
        itens.push(span.textContent.trim());
    });
    return itens;
}

async function criarLancamentoDoFormulario() {
    const colId = document.getElementById('unif-colaborador').value;
    const obrId = document.getElementById('unif-obra').value;
    if (!colId || !obrId) {
        showToast('Selecione colaborador e obra!');
        return null;
    }

    const col = colaboradores.find(c => c.id === colId);
    const obr = obras.find(o => o.id === obrId);
    const combustivel = extrairValorMoeda(document.getElementById('unif-total-comb').textContent);
    const refeicoes = extrairValorMoeda(document.getElementById('unif-total-ref').textContent);
    const outros = extrairValorMoeda(document.getElementById('unif-total-outros').textContent);
    const total = extrairValorMoeda(document.getElementById('unif-total-geral').textContent);
    const km = parseFloat(document.getElementById('unif-total-km').textContent) || 0;

    const anexos = [];
    const kmDetalhes = [];
    const refeicoesDetalhes = [];
    const outrosDetalhes = [];

    const kmRows = Array.from(document.querySelectorAll('.km-day-row'));
    for (let i = 0; i < kmRows.length; i++) {
        const row = kmRows[i];
        const rowLabel = `Trajeto #${i + 1}`;
        const rowAttachments = await buildAttachmentRecords(row.querySelector('.km-anexo')?.files || [], {
            categoria: 'Combustível',
            origem: rowLabel
        });
        anexos.push(...rowAttachments);
        kmDetalhes.push({
            titulo: rowLabel,
            data: row.querySelector('.km-data')?.value || '',
            origem: row.querySelector('.km-origem')?.value || '',
            destino: row.querySelector('.km-destino')?.value || '',
            kmIda: parseFloat(row.querySelector('.km-ida')?.value) || 0,
            kmVolta: parseFloat(row.querySelector('.km-volta')?.value) || 0,
            kmTotal: (parseFloat(row.querySelector('.km-ida')?.value) || 0) + (parseFloat(row.querySelector('.km-volta')?.value) || 0),
            anexos: rowAttachments
        });
    }

    const refRows = Array.from(document.querySelectorAll('.ref-day-row'));
    for (let i = 0; i < refRows.length; i++) {
        const row = refRows[i];
        const idx = row.id.split('-')[2];
        const rowLabel = `Viagem #${i + 1}`;
        const rowAttachments = await buildAttachmentRecords(row.querySelector('.ref-anexo')?.files || [], {
            categoria: 'Refeições',
            origem: rowLabel
        });
        anexos.push(...rowAttachments);
        refeicoesDetalhes.push({
            titulo: rowLabel,
            saidaData: row.querySelector('.ref-d-saida')?.value || '',
            saidaHora: row.querySelector('.ref-h-saida')?.value || '',
            chegadaData: row.querySelector('.ref-d-chegada')?.value || '',
            chegadaHora: row.querySelector('.ref-h-chegada')?.value || '',
            itens: getMealItemsFromRow(row, idx),
            anexos: rowAttachments
        });
    }

    const outrosRows = Array.from(document.querySelectorAll('.outro-row'));
    for (let i = 0; i < outrosRows.length; i++) {
        const row = outrosRows[i];
        const rowLabel = `Outro #${i + 1}`;
        const rowAttachments = await buildAttachmentRecords(row.querySelector('.out-anexo')?.files || [], {
            categoria: 'Outros',
            origem: rowLabel
        });
        anexos.push(...rowAttachments);
        outrosDetalhes.push({
            titulo: rowLabel,
            data: row.querySelector('.out-data')?.value || '',
            categoria: row.querySelector('.out-cat')?.value || '',
            descricao: row.querySelector('.out-desc')?.value || '',
            valor: parseFloat(row.querySelector('.out-vlr')?.value) || 0,
            anexos: rowAttachments
        });
    }

    const totalAnexosBytes = anexos.reduce((sum, item) => sum + (item?.tamanho || 0), 0);
    if (totalAnexosBytes > MAX_ATTACHMENTS_TOTAL_BYTES) {
        throw new Error('O volume total de anexos excede o limite recomendado de 4,5 MB por lançamento.');
    }

    return {
        id: generateId('l_'),
        colabId: col.id,
        colab: col.nome,
        matricula: col.matricula,
        cargo: col.cargo,
        obraId: obr.id,
        obra: obr.nome,
        periodo: document.getElementById('unif-periodo').value || '',
        mes: document.getElementById('unif-mes-referencia').value,
        total,
        km,
        combustivel,
        refeicoes,
        outros,
        status: 'pendente',
        anexos,
        kmDetalhes,
        refeicoesDetalhes,
        outrosDetalhes
    };
}

function normalizarLancamento(l) {
    if (!l) return null;
    const col = colaboradores.find(c => c.id === l.colabId || c.nome === l.colab);
    const obra = obras.find(o => o.id === l.obraId || o.nome === l.obra);
    return {
        ...l,
        colabId: l.colabId || col?.id || '',
        colab: l.colab || col?.nome || 'N/A',
        matricula: l.matricula || col?.matricula || 'N/A',
        cargo: l.cargo || col?.cargo || 'N/A',
        obraId: l.obraId || obra?.id || '',
        obra: l.obra || obra?.nome || 'N/A',
        periodo: l.periodo || '',
        combustivel: l.combustivel || 0,
        refeicoes: l.refeicoes || 0,
        outros: l.outros || 0,
        anexos: Array.isArray(l.anexos) ? l.anexos : [],
        kmDetalhes: Array.isArray(l.kmDetalhes) ? l.kmDetalhes : [],
        refeicoesDetalhes: Array.isArray(l.refeicoesDetalhes) ? l.refeicoesDetalhes : [],
        outrosDetalhes: Array.isArray(l.outrosDetalhes) ? l.outrosDetalhes : []
    };
}

async function salvarLancamentoUnificado(e) {
    e.preventDefault();
    const payload = await criarLancamentoDoFormulario();
    if (!payload) return;

    try {
        await apiRequest('upsertLancamento', { lancamento: payload });
        lancamentos = [payload, ...lancamentos.filter(item => item.id !== payload.id)];
        ordenarColecoes();
        salvarCacheLocal();
        showToast('Lançamento salvo com persistência permanente!');
        resetarFormularioLancamento();
        atualizarDashboard();
        renderAprovacoes();
        filtrarRelatorio();
        renderPainelMestre();
        navigate('dashboard');
    } catch (error) {
        console.error(error);
        showToast('Erro ao salvar no banco compartilhado. Tente novamente.');
    }
}

function resetarFormularioLancamento() {
    const form = document.getElementById('form-lancamento-unificado');
    if (form) form.reset();
    document.getElementById('km-rows-container').innerHTML = '';
    document.getElementById('ref-rows-container').innerHTML = '';
    document.getElementById('outros-rows-container').innerHTML = '';
    document.getElementById('unif-total-km').textContent = '0.0';
    document.getElementById('unif-total-comb').textContent = formatMoeda(0);
    document.getElementById('unif-total-ref').textContent = formatMoeda(0);
    document.getElementById('unif-total-outros').textContent = formatMoeda(0);
    document.getElementById('unif-total-geral').textContent = formatMoeda(0);
    document.getElementById('unif-periodo').value = '';
    document.getElementById('unif-matricula').value = '';
    document.getElementById('unif-funcao').value = '';
    refeicoesExcluidas = {};
    kmCount = 0;
    refCount = 0;
    outroCount = 0;
    document.getElementById('unif-mes-referencia').value = new Date().toISOString().slice(0, 7);
    adicionarLinhaKm();
    adicionarLinhaRefeicao();
    adicionarLinhaOutro();
    atualizarTotais();
}

function atualizarDashboard() {
    let total = 0;
    let km = 0;
    lancamentos.forEach(l => {
        total += l.total || 0;
        km += l.km || 0;
    });
    document.getElementById('dash-total-valor').textContent = formatMoeda(total);
    document.getElementById('dash-total-km').textContent = km.toFixed(1);
    document.getElementById('dash-colab').textContent = colaboradores.length;
    document.getElementById('dash-obras').textContent = obras.length;

    if (typeof Chart === 'undefined') return;
    const chartCanvas = document.getElementById('chart-evolucao');
    if (!chartCanvas) return;
    const ctxE = chartCanvas.getContext('2d');
    if (window.myChartE) window.myChartE.destroy();
    const meses = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
    const valores = meses.map((m, i) => {
        const mes = String(i + 1).padStart(2, '0');
        return lancamentos.filter(l => (l.mes || '').endsWith('-' + mes)).reduce((s, l) => s + (l.total || 0), 0);
    });
    window.myChartE = new Chart(ctxE, {
        type: 'bar',
        data: {
            labels: meses,
            datasets: [{
                label: 'Total (R$)',
                data: valores,
                backgroundColor: '#f97316'
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false
        }
    });
}

function renderAprovacoes() {
    const tbody = document.getElementById('tbody-aprovacoes');
    tbody.innerHTML = lancamentos.filter(l => l.status === 'pendente').map(l => `
        <tr>
            <td>${escapeHtml(l.colab)}</td>
            <td>${escapeHtml(l.obra)}</td>
            <td>${escapeHtml(l.mes)}</td>
            <td>${formatMoeda(l.total)}</td>
            <td><span class="badge badge-pendente">Pendente</span></td>
            <td>
                <div style="display:flex;gap:8px;flex-wrap:wrap">
                    <button class="btn btn-sm btn-info" onclick="verDetalhesAprovacao('${l.id}')"><i class="fas fa-eye"></i> Analisar</button>
                    <button class="btn btn-sm btn-danger" onclick="gerarPDFAprovacao('${l.id}')"><i class="fas fa-file-pdf"></i> PDF</button>
                    <button class="btn btn-sm btn-danger" onclick="excluirLancamento('${l.id}')"><i class="fas fa-trash"></i> Excluir</button>
                </div>
            </td>
        </tr>
    `).join('') || '<tr><td colspan="6" style="text-align:center;padding:20px">Nada pendente</td></tr>';
}

function verDetalhesAprovacao(id) {
    const lancamento = normalizarLancamento(lancamentos.find(x => x.id === id));
    if (!lancamento) return showToast('Lançamento não encontrado!');
    aprovacaoAtualId = id;

    const html = `
        <div class="approval-summary-grid">
            <div class="approval-summary-card"><span>Colaborador</span><strong>${escapeHtml(lancamento.colab)}</strong></div>
            <div class="approval-summary-card"><span>Matrícula</span><strong>${escapeHtml(lancamento.matricula || 'N/A')}</strong></div>
            <div class="approval-summary-card"><span>Cargo</span><strong>${escapeHtml(lancamento.cargo || 'N/A')}</strong></div>
            <div class="approval-summary-card"><span>Obra</span><strong>${escapeHtml(lancamento.obra)}</strong></div>
            <div class="approval-summary-card"><span>Período</span><strong>${escapeHtml(lancamento.periodo || '-')}</strong></div>
            <div class="approval-summary-card"><span>Mês referência</span><strong>${escapeHtml(lancamento.mes)}</strong></div>
            <div class="approval-summary-card"><span>Combustível</span><strong>${formatMoeda(lancamento.combustivel || 0)}</strong></div>
            <div class="approval-summary-card"><span>Refeições</span><strong>${formatMoeda(lancamento.refeicoes || 0)}</strong></div>
            <div class="approval-summary-card"><span>Outros</span><strong>${formatMoeda(lancamento.outros || 0)}</strong></div>
            <div class="approval-summary-card approval-summary-card--accent"><span>Total</span><strong>${formatMoeda(lancamento.total || 0)}</strong></div>
        </div>

        <div class="approval-section">
            <h3>Formulário enviado</h3>
            ${montarTabelaKmHtml(lancamento.kmDetalhes)}
            ${montarTabelaRefeicoesHtml(lancamento.refeicoesDetalhes)}
            ${montarTabelaOutrosHtml(lancamento.outrosDetalhes)}
        </div>

        <div class="approval-section">
            <h3>Anexos completos para análise</h3>
            ${montarAnexosHtml(lancamento.anexos)}
        </div>
    `;

    document.getElementById('approval-details-content').innerHTML = html;
    openModal('modal-aprovacao-detalhes');
}

function aprovarLancamentoAtual(status) {
    if (!aprovacaoAtualId) return;
    alterarStatus(aprovacaoAtualId, status);
    closeModal('modal-aprovacao-detalhes');
}

function montarTabelaKmHtml(kmDetalhes = []) {
    if (!kmDetalhes.length) return '<p class="approval-empty">Nenhum trajeto informado.</p>';
    return `
        <div class="table-wrap approval-table-wrap">
            <table>
                <thead>
                    <tr><th>Trajeto</th><th>Data</th><th>Origem</th><th>Destino</th><th>KM</th><th>Anexos</th></tr>
                </thead>
                <tbody>
                    ${kmDetalhes.map(item => `
                        <tr>
                            <td>${escapeHtml(item.titulo || '-')}</td>
                            <td>${escapeHtml(formatDateBR(item.data))}</td>
                            <td>${escapeHtml(item.origem || '-')}</td>
                            <td>${escapeHtml(item.destino || '-')}</td>
                            <td>${(item.kmTotal || 0).toFixed(1)}</td>
                            <td>${(item.anexos || []).length}</td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        </div>
    `;
}

function montarTabelaRefeicoesHtml(refeicoesDetalhes = []) {
    if (!refeicoesDetalhes.length) return '<p class="approval-empty">Nenhuma viagem de refeições informada.</p>';
    return `
        <div class="table-wrap approval-table-wrap">
            <table>
                <thead>
                    <tr><th>Viagem</th><th>Saída</th><th>Chegada</th><th>Itens elegíveis</th><th>Anexos</th></tr>
                </thead>
                <tbody>
                    ${refeicoesDetalhes.map(item => `
                        <tr>
                            <td>${escapeHtml(item.titulo || '-')}</td>
                            <td>${escapeHtml(item.saidaData ? `${formatDateBR(item.saidaData)} ${item.saidaHora || ''}` : '-')}</td>
                            <td>${escapeHtml(item.chegadaData ? `${formatDateBR(item.chegadaData)} ${item.chegadaHora || ''}` : '-')}</td>
                            <td>${item.itens && item.itens.length ? item.itens.map(i => `<span class="approval-tag">${escapeHtml(i)}</span>`).join(' ') : '-'}</td>
                            <td>${(item.anexos || []).length}</td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        </div>
    `;
}

function montarTabelaOutrosHtml(outrosDetalhes = []) {
    if (!outrosDetalhes.length) return '<p class="approval-empty">Nenhum outro lançamento informado.</p>';
    return `
        <div class="table-wrap approval-table-wrap">
            <table>
                <thead>
                    <tr><th>Lançamento</th><th>Data</th><th>Categoria</th><th>Descrição</th><th>Valor</th><th>Anexos</th></tr>
                </thead>
                <tbody>
                    ${outrosDetalhes.map(item => `
                        <tr>
                            <td>${escapeHtml(item.titulo || '-')}</td>
                            <td>${escapeHtml(formatDateBR(item.data))}</td>
                            <td>${escapeHtml(item.categoria || '-')}</td>
                            <td>${escapeHtml(item.descricao || '-')}</td>
                            <td>${formatMoeda(item.valor || 0)}</td>
                            <td>${(item.anexos || []).length}</td>
                        </tr>
                    `).join('')}
                </tbody>
            </table>
        </div>
    `;
}

function montarAnexosHtml(anexos = []) {
    if (!anexos.length) return '<p class="approval-empty">Nenhum anexo enviado neste lançamento.</p>';
    return anexos.map((anexo, index) => {
        let preview = `<div class="approval-file-fallback"><i class="fas fa-paperclip"></i><span>Visualização indisponível. Use o PDF ou faça download do arquivo.</span></div>`;
        if (anexo.kind === 'image') {
            preview = `<img class="approval-image-preview" src="${anexo.dataUrl}" alt="${escapeHtml(anexo.nome)}">`;
        } else if (anexo.kind === 'pdf') {
            preview = `<iframe class="approval-pdf-frame" src="${anexo.dataUrl}"></iframe>`;
        }
        return `
            <div class="approval-attachment-card">
                <div class="approval-attachment-meta">
                    <div>
                        <strong>Anexo ${index + 1}: ${escapeHtml(anexo.nome)}</strong>
                        <div class="approval-attachment-submeta">${escapeHtml(anexo.categoria || 'Anexo')} • ${escapeHtml(anexo.origem || '-')} • ${formatBytes(anexo.tamanho || 0)}</div>
                    </div>
                    <a class="btn btn-secondary btn-sm" href="${anexo.dataUrl}" download="${escapeHtml(anexo.nome)}"><i class="fas fa-download"></i> Baixar</a>
                </div>
                <div class="approval-attachment-preview">${preview}</div>
            </div>
        `;
    }).join('');
}

function filtrarRelatorio() {
    const colabFiltro = document.getElementById('rel-colaborador').value;
    const obraFiltro = document.getElementById('rel-obra').value;
    const mesFiltro = document.getElementById('rel-mes').value;
    const statusFiltro = document.getElementById('rel-status').value;

    const dados = lancamentos.filter(l => {
        if (colabFiltro && l.colabId !== colabFiltro) return false;
        if (obraFiltro && l.obraId !== obraFiltro) return false;
        if (mesFiltro && l.mes !== mesFiltro) return false;
        if (statusFiltro && l.status !== statusFiltro) return false;
        return true;
    });

    const tbody = document.getElementById('tbody-relatorio');
    tbody.innerHTML = dados.map(l => `
        <tr>
            <td>${escapeHtml(l.colab)}</td>
            <td>${escapeHtml(l.obra)}</td>
            <td>${escapeHtml(l.mes)}</td>
            <td>${formatMoeda(l.total)}</td>
            <td><span class="badge badge-${escapeHtml(l.status)}">${escapeHtml(l.status)}</span></td>
            <td>
                <div style="display:flex;gap:8px;flex-wrap:wrap">
                    <button class="btn btn-sm btn-info" onclick="gerarPDFIndividual('${l.id}')"><i class="fas fa-file-pdf"></i> PDF</button>
                    <button class="btn btn-sm btn-danger" onclick="excluirLancamento('${l.id}')"><i class="fas fa-trash"></i> Excluir</button>
                </div>
            </td>
        </tr>
    `).join('') || '<tr><td colspan="6" style="text-align:center;padding:20px">Sem dados</td></tr>';
    document.getElementById('btn-pdf-relatorio').style.display = dados.length ? 'inline-flex' : 'none';
}

function renderPainelMestre() {
    let t = 0;
    lancamentos.forEach(l => t += l.total || 0);
    document.getElementById('pm-total').textContent = formatMoeda(t);
    document.getElementById('tbody-painel').innerHTML = lancamentos.map(l => `
        <tr>
            <td>${escapeHtml(l.colab)}</td>
            <td>${escapeHtml(l.obra)}</td>
            <td>${escapeHtml(l.mes)}</td>
            <td>${formatMoeda(l.total)}</td>
            <td><span class="badge badge-${escapeHtml(l.status)}">${escapeHtml(l.status)}</span></td>
            <td>
                <div style="display:flex;gap:8px;flex-wrap:wrap">
                    <button class="btn btn-sm btn-info" onclick="gerarPDFIndividual('${l.id}')"><i class="fas fa-file-pdf"></i> PDF</button>
                    <button class="btn btn-sm btn-danger" onclick="excluirLancamento('${l.id}')"><i class="fas fa-trash"></i> Excluir</button>
                </div>
            </td>
        </tr>
    `).join('') || '<tr><td colspan="6" style="text-align:center;padding:20px">Sem dados</td></tr>';
}

async function excluirLancamento(id) {
    const lancamento = lancamentos.find(x => x.id === id);
    if (!lancamento) return showToast('Lançamento não encontrado!');
    if (!confirm(`Tem certeza que deseja excluir o lançamento de ${lancamento.colab} referente a ${lancamento.mes}?`)) return;

    try {
        await apiRequest('deleteLancamento', { id });
        lancamentos = lancamentos.filter(l => l.id !== id);
        if (aprovacaoAtualId === id) {
            aprovacaoAtualId = null;
            closeModal('modal-aprovacao-detalhes');
        }
        salvarCacheLocal();
        atualizarDashboard();
        renderAprovacoes();
        filtrarRelatorio();
        renderPainelMestre();
        showToast('Lançamento excluído com sucesso!');
    } catch (error) {
        console.error(error);
        showToast('Não foi possível excluir no banco compartilhado.');
    }
}

async function alterarStatus(id, st) {
    const l = lancamentos.find(x => x.id === id);
    if (!l) return;

    try {
        await apiRequest('updateLancamentoStatus', { id, status: st });
        l.status = st;
        l.updatedAt = new Date().toISOString();
        salvarCacheLocal();
        showToast('Status atualizado para: ' + st);
        renderAprovacoes();
        renderPainelMestre();
        atualizarDashboard();
        filtrarRelatorio();
    } catch (error) {
        console.error(error);
        showToast('Não foi possível atualizar o status no banco compartilhado.');
    }
}

function popularSelects() {
    const cSel = document.getElementById('unif-colaborador');
    const oSel = document.getElementById('unif-obra');
    const optsC = colaboradores.map(c => `<option value="${c.id}">${c.nome}</option>`).join('');
    const optsO = obras.map(o => `<option value="${o.id}">${o.nome}</option>`).join('');
    cSel.innerHTML = '<option value="">Selecione...</option>' + optsC;
    oSel.innerHTML = '<option value="">Selecione...</option>' + optsO;
    document.getElementById('rel-colaborador').innerHTML = '<option value="">Todos</option>' + optsC;
    document.getElementById('rel-obra').innerHTML = '<option value="">Todas</option>' + optsO;
}

function preencherDadosColaborador() {
    const c = colaboradores.find(x => x.id === document.getElementById('unif-colaborador').value);
    document.getElementById('unif-matricula').value = c ? c.matricula : '';
    document.getElementById('unif-funcao').value = c ? c.cargo : '';
}

async function salvarColaborador() {
    const n = document.getElementById('colab-nome').value;
    const c = document.getElementById('colab-cargo').value;
    const m = document.getElementById('colab-matricula').value;
    if (!n) return;

    const novoColaborador = {
        id: generateId('c_'),
        nome: n,
        cargo: c,
        matricula: m,
        status: 'ativo'
    };

    try {
        await apiRequest('upsertColaborador', { colaborador: novoColaborador });
        colaboradores = [...colaboradores.filter(item => item.id !== novoColaborador.id), novoColaborador];
        ordenarColecoes();
        salvarCacheLocal();
        closeModal('modal-colaborador');
        showToast('Colaborador salvo!');
        popularSelects();
        renderColaboradores();
    } catch (error) {
        console.error(error);
        showToast('Não foi possível salvar o colaborador no banco compartilhado.');
    }
}

function renderColaboradores() {
    document.getElementById('tbody-colaboradores').innerHTML = colaboradores.map(c => `
        <tr>
            <td>${escapeHtml(c.nome)}</td>
            <td>${escapeHtml(c.cargo)}</td>
            <td>${escapeHtml(c.matricula)}</td>
            <td><span class="badge badge-ativa">Ativo</span></td>
            <td><button class="btn btn-sm btn-danger" onclick="excluirColaborador('${c.id}')"><i class="fas fa-trash"></i> Excluir</button></td>
        </tr>
    `).join('');
}

async function excluirColaborador(id) {
    if (!confirm('Tem certeza que deseja excluir este colaborador?')) return;

    try {
        await apiRequest('deleteColaborador', { id });
        colaboradores = colaboradores.filter(c => c.id !== id);
        salvarCacheLocal();
        renderColaboradores();
        popularSelects();
        showToast('Colaborador excluído!');
    } catch (error) {
        console.error(error);
        showToast('Não foi possível excluir o colaborador do banco compartilhado.');
    }
}

async function salvarObra() {
    const n = document.getElementById('obra-nome').value;
    const r = document.getElementById('obra-responsavel').value;
    if (!n) return;

    const novaObra = {
        id: generateId('o_'),
        nome: n,
        responsavel: r,
        status: 'ativa'
    };

    try {
        await apiRequest('upsertObra', { obra: novaObra });
        obras = [...obras.filter(item => item.id !== novaObra.id), novaObra];
        ordenarColecoes();
        salvarCacheLocal();
        closeModal('modal-obra');
        showToast('Obra salva!');
        popularSelects();
        renderObras();
    } catch (error) {
        console.error(error);
        showToast('Não foi possível salvar a obra no banco compartilhado.');
    }
}

function renderObras() {
    document.getElementById('tbody-obras').innerHTML = obras.map(o => `
        <tr>
            <td>${escapeHtml(o.nome)}</td>
            <td>${escapeHtml(o.responsavel)}</td>
            <td><span class="badge badge-ativa">Ativa</span></td>
            <td><button class="btn btn-sm btn-danger" onclick="excluirObra('${o.id}')"><i class="fas fa-trash"></i> Excluir</button></td>
        </tr>
    `).join('');
}

async function excluirObra(id) {
    if (!confirm('Tem certeza que deseja excluir esta obra?')) return;

    try {
        await apiRequest('deleteObra', { id });
        obras = obras.filter(o => o.id !== id);
        salvarCacheLocal();
        renderObras();
        popularSelects();
        showToast('Obra excluída!');
    } catch (error) {
        console.error(error);
        showToast('Não foi possível excluir a obra do banco compartilhado.');
    }
}

async function salvarParametros() {
    const novosParametros = {
        ...parametros,
        vlrKm: parseFloat(document.getElementById('param-vlr-km').value) || 1.3,
        cafe: parseFloat(document.getElementById('param-cafe').value) || 20,
        almoco: parseFloat(document.getElementById('param-almoco').value) || 50,
        jantar: parseFloat(document.getElementById('param-jantar').value) || 50,
        gestorObra: document.getElementById('param-gestor-obra').value,
        admObras: document.getElementById('param-adm-obras').value,
        cafeInicio: document.getElementById('param-cafe-inicio').value,
        cafeFim: document.getElementById('param-cafe-fim').value,
        almocoInicio: document.getElementById('param-almoco-inicio').value,
        almocoFim: document.getElementById('param-almoco-fim').value,
        jantarInicio: document.getElementById('param-jantar-inicio').value,
        jantarFim: document.getElementById('param-jantar-fim').value
    };

    try {
        await apiRequest('saveParametros', { parametros: novosParametros });
        parametros = novosParametros;
        document.getElementById('unif-vlr-km').textContent = formatMoeda(parametros.vlrKm);
        salvarCacheLocal();
        atualizarTotais();
        showToast('Parâmetros salvos!');
    } catch (error) {
        console.error(error);
        showToast('Não foi possível salvar os parâmetros no banco compartilhado.');
    }
}

/* LÓGICA DE PDF RESTAURADA DO ORIGINAL */

function getLogoImageFormat() {
    if (!LOGO_BASE64) return 'PNG';
    if (LOGO_BASE64.startsWith('data:image/jpeg')) return 'JPEG';
    return 'PNG';
}

function adicionarLogoNoPDF(doc) {
    if (!LOGO_BASE64) return;
    try {
        if (doc.roundedRect) {
            doc.setFillColor(255, 255, 255);
            doc.roundedRect(170, 8, 28, 28, 3, 3, 'F');
        } else {
            doc.setFillColor(255, 255, 255);
            doc.rect(170, 8, 28, 28, 'F');
        }
        doc.addImage(LOGO_BASE64, getLogoImageFormat(), 172, 10, 24, 24);
    } catch (error) {
        console.warn('Não foi possível adicionar o logo ao PDF.', error);
    }
}

function desenharCabecalhoPDF(doc, titulo, subtitulo) {
    doc.setFillColor(15, 23, 42);
    doc.rect(0, 0, 210, 45, 'F');
    adicionarLogoNoPDF(doc);
    doc.setTextColor(255);
    doc.setFont(undefined, 'bold');
    doc.setFontSize(18);
    doc.text(titulo, 18, 18);
    doc.setFont(undefined, 'normal');
    doc.setFontSize(10);
    doc.text(subtitulo, 18, 27);
}

function desenharCabecalhoAnexoPDF(doc, titulo, subtitulo) {
    doc.setFillColor(15, 23, 42);
    doc.rect(0, 0, 210, 20, 'F');
    adicionarLogoNoPDF(doc);
    doc.setTextColor(255);
    doc.setFont(undefined, 'bold');
    doc.setFontSize(12);
    doc.text(titulo, 15, 10);
    doc.setFont(undefined, 'normal');
    doc.setFontSize(9);
    doc.text(subtitulo, 15, 16);
}

function gerarCorpoResumoPDF(doc, lancamento) {
    doc.setTextColor(0);
    doc.setFontSize(11);
    doc.setFont(undefined, 'bold');
    doc.text('IDENTIFICAÇÃO', 15, 58);
    doc.setFont(undefined, 'normal');
    doc.setFontSize(10);
    doc.text(`Colaborador: ${lancamento.colab || 'N/A'}`, 15, 66);
    doc.text(`Matrícula: ${lancamento.matricula || 'N/A'}`, 15, 73);
    doc.text(`Cargo: ${lancamento.cargo || 'N/A'}`, 105, 66);
    doc.text(`Obra: ${lancamento.obra || 'N/A'}`, 105, 73);
    doc.text(`Período: ${lancamento.periodo || '-'}`, 15, 80);
    doc.text(`Mês Ref.: ${lancamento.mes || '-'}`, 105, 80);

    doc.setFont(undefined, 'bold');
    doc.setFontSize(11);
    doc.text('RESUMO DE DESPESAS', 15, 94);
    doc.setFont(undefined, 'normal');
    doc.setFontSize(10);
    doc.text(`Combustível (KM): ${formatMoeda(lancamento.combustivel || 0)}`, 15, 102);
    doc.text(`Refeições: ${formatMoeda(lancamento.refeicoes || 0)}`, 15, 109);
    doc.text(`Outros lançamentos: ${formatMoeda(lancamento.outros || 0)}`, 15, 116);

    doc.setFillColor(249, 115, 22);
    doc.rect(15, 124, 180, 10, 'F');
    doc.setTextColor(255);
    doc.setFont(undefined, 'bold');
    doc.setFontSize(12);
    doc.text(`TOTAL A PAGAR: ${formatMoeda(lancamento.total || 0)}`, 105, 131, { align: 'center' });

    let cursorY = 144;
    const hasAutoTable = typeof doc.autoTable === 'function';

    if (hasAutoTable && lancamento.kmDetalhes?.length) {
        doc.setTextColor(0);
        doc.setFont(undefined, 'bold');
        doc.setFontSize(11);
        doc.text('DETALHES DE COMBUSTÍVEL', 15, cursorY);
        doc.autoTable({
            startY: cursorY + 4,
            head: [['Percurso', 'Data', 'Origem', 'Destino', 'KM']],
            body: lancamento.kmDetalhes.map(item => [
                item.titulo || '-',
                formatDateBR(item.data),
                item.origem || '-',
                item.destino || '-',
                (item.kmTotal || 0).toFixed(1)
            ]),
            styles: { fontSize: 8, cellPadding: 2 },
            headStyles: { fillColor: [15, 23, 42] },
            margin: { left: 15, right: 15 }
        });
        cursorY = doc.lastAutoTable.finalY + 8;
    }

    if (hasAutoTable && lancamento.refeicoesDetalhes?.length) {
        if (cursorY > 235) {
            doc.addPage();
            desenharCabecalhoAnexoPDF(doc, 'DETALHES COMPLEMENTARES', 'Continuação do formulário');
            cursorY = 30;
        }
        doc.setTextColor(0);
        doc.setFont(undefined, 'bold');
        doc.setFontSize(11);
        doc.text('DETALHES DE REFEIÇÕES', 15, cursorY);
        doc.autoTable({
            startY: cursorY + 4,
            head: [['Viagem', 'Saída', 'Chegada', 'Itens']],
            body: lancamento.refeicoesDetalhes.map(item => [
                item.titulo || '-',
                item.saidaData ? `${formatDateBR(item.saidaData)} ${item.saidaHora || ''}` : '-',
                item.chegadaData ? `${formatDateBR(item.chegadaData)} ${item.chegadaHora || ''}` : '-',
                item.itens?.join(', ') || '-'
            ]),
            styles: { fontSize: 8, cellPadding: 2 },
            headStyles: { fillColor: [15, 23, 42] },
            margin: { left: 15, right: 15 }
        });
        cursorY = doc.lastAutoTable.finalY + 8;
    }

    if (hasAutoTable && lancamento.outrosDetalhes?.length) {
        if (cursorY > 235) {
            doc.addPage();
            desenharCabecalhoAnexoPDF(doc, 'DETALHES COMPLEMENTARES', 'Continuação do formulário');
            cursorY = 30;
        }
        doc.setTextColor(0);
        doc.setFont(undefined, 'bold');
        doc.setFontSize(11);
        doc.text('OUTROS LANÇAMENTOS', 15, cursorY);
        doc.autoTable({
            startY: cursorY + 4,
            head: [['Lançamento', 'Data', 'Categoria', 'Valor']],
            body: lancamento.outrosDetalhes.map(item => [
                item.titulo || '-',
                formatDateBR(item.data),
                item.categoria || '-',
                formatMoeda(item.valor || 0)
            ]),
            styles: { fontSize: 8, cellPadding: 2 },
            headStyles: { fillColor: [15, 23, 42] },
            margin: { left: 15, right: 15 }
        });
        cursorY = doc.lastAutoTable.finalY + 8;
    }

    if (cursorY > 225) {
        doc.addPage();
        desenharCabecalhoAnexoPDF(doc, 'ASSINATURAS E APROVAÇÕES', 'Espaço para validação do processo');
        cursorY = 40;
    }

    doc.setTextColor(0);
    doc.setFont(undefined, 'bold');
    doc.setFontSize(11);
    doc.text('ASSINATURAS E APROVAÇÕES', 15, cursorY);
    doc.setFont(undefined, 'normal');
    cursorY += 14;

    doc.line(15, cursorY, 60, cursorY);
    doc.text('Colaborador', 15, cursorY + 6);
    doc.text('Data: ___/___/____', 15, cursorY + 12);
    doc.line(75, cursorY, 120, cursorY);
    doc.text('Gestor da Obra', 75, cursorY + 6);
    doc.text('Data: ___/___/____', 75, cursorY + 12);
    doc.line(135, cursorY, 195, cursorY);
    doc.text('Adm. de Obras', 135, cursorY + 6);
    doc.text('Data: ___/___/____', 135, cursorY + 12);
}

function inferImageFormatFromDataUrl(dataUrl = '') {
    if (dataUrl.startsWith('data:image/jpeg')) return 'JPEG';
    return 'PNG';
}

function getImageDimensions(dataUrl) {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => resolve({ width: img.width, height: img.height });
        img.onerror = reject;
        img.src = dataUrl;
    });
}

function fitInside(width, height, maxWidth, maxHeight) {
    const ratio = Math.min(maxWidth / width, maxHeight / height);
    return {
        width: width * ratio,
        height: height * ratio
    };
}

function dataUrlToUint8Array(dataUrl) {
    const base64 = dataUrl.split(',')[1] || '';
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
    return bytes;
}

async function renderPdfToImages(dataUrl) {
    if (!window.pdfjsLib) throw new Error('pdf.js não disponível');
    const pdf = await window.pdfjsLib.getDocument({ data: dataUrlToUint8Array(dataUrl) }).promise;
    const images = [];
    for (let pageNum = 1; pageNum <= pdf.numPages; pageNum++) {
        const page = await pdf.getPage(pageNum);
        const viewport = page.getViewport({ scale: 1.6 });
        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');
        canvas.width = viewport.width;
        canvas.height = viewport.height;
        await page.render({ canvasContext: context, viewport }).promise;
        images.push(canvas.toDataURL('image/jpeg', 0.92));
    }
    return images;
}

async function adicionarPaginaImagemAnexo(doc, anexo, titulo, subtitulo, imageDataUrl) {
    doc.addPage();
    desenharCabecalhoAnexoPDF(doc, titulo, subtitulo);
    const dims = await getImageDimensions(imageDataUrl);
    const ajustado = fitInside(dims.width, dims.height, 180, 250);
    const x = (210 - ajustado.width) / 2;
    const y = 28 + ((250 - ajustado.height) / 2);
    doc.addImage(imageDataUrl, inferImageFormatFromDataUrl(imageDataUrl), x, y, ajustado.width, ajustado.height);
}

async function adicionarAnexosAoPDF(doc, anexos = []) {
    for (let index = 0; index < anexos.length; index++) {
        const anexo = anexos[index];
        const tituloBase = `ANEXO ${index + 1} • ${anexo.nome}`;
        const subtituloBase = `${anexo.categoria || 'Anexo'} • ${anexo.origem || '-'} • ${formatBytes(anexo.tamanho || 0)}`;

        if (anexo.kind === 'image') {
            await adicionarPaginaImagemAnexo(doc, anexo, tituloBase, subtituloBase, anexo.dataUrl);
            continue;
        }

        if (anexo.kind === 'pdf') {
            try {
                const imagens = await renderPdfToImages(anexo.dataUrl);
                for (let pageIndex = 0; pageIndex < imagens.length; pageIndex++) {
                    await adicionarPaginaImagemAnexo(
                        doc,
                        anexo,
                        tituloBase,
                        `${subtituloBase} • Página ${pageIndex + 1}/${imagens.length}`,
                        imagens[pageIndex]
                    );
                }
                continue;
            } catch (error) {
                console.warn('Falha ao renderizar PDF do anexo.', error);
            }
        }

        doc.addPage();
        desenharCabecalhoAnexoPDF(doc, tituloBase, subtituloBase);
        doc.setTextColor(0);
        doc.setFont(undefined, 'bold');
        doc.setFontSize(12);
        doc.text('Não foi possível incorporar este arquivo visualmente no PDF.', 15, 40);
        doc.setFont(undefined, 'normal');
        doc.setFontSize(10);
        doc.text(`Arquivo: ${anexo.nome}`, 15, 52);
        doc.text(`Tipo: ${anexo.tipo || 'desconhecido'}`, 15, 59);
        doc.text(`Tamanho: ${formatBytes(anexo.tamanho || 0)}`, 15, 66);
    }
}

async function gerarPdfCompletoLancamento(lancamento, fileName, subtituloCabecalho) {
    const { jsPDF } = window.jspdf;
    const payload = normalizarLancamento(lancamento);
    const doc = new jsPDF('p', 'mm', 'a4');

    desenharCabecalhoPDF(doc, 'GUIA DE REEMBOLSO DE VIAGENS', subtituloCabecalho);
    gerarCorpoResumoPDF(doc, payload);
    await adicionarAnexosAoPDF(doc, payload.anexos || []);
    doc.save(fileName);
}

async function emitirPDFAssinatura() {
    const lancamento = await criarLancamentoDoFormulario();
    if (!lancamento) return;
    await gerarPdfCompletoLancamento(lancamento, `Guia_Reembolso_${lancamento.colab}_${lancamento.mes}.pdf`, 'Documento de reembolso para assinatura');
    showToast('PDF de assinatura gerado com sucesso!');
}

async function gerarPDFAprovacao(id) {
    const lancamento = lancamentos.find(x => x.id === id);
    if (!lancamento) return showToast('Lançamento não encontrado!');
    await gerarPdfCompletoLancamento(lancamento, `Revisao_${lancamento.colab}_${lancamento.mes}.pdf`, 'Documento para revisão gerencial');
    showToast('PDF de revisão gerado com sucesso!');
}

async function gerarPDFIndividual(id) {
    const lancamento = lancamentos.find(x => x.id === id);
    if (!lancamento) return showToast('Lançamento não encontrado!');
    await gerarPdfCompletoLancamento(lancamento, `Reembolso_${lancamento.colab}_${lancamento.mes}.pdf`, 'Comprovante de lançamento');
    showToast('PDF gerado com sucesso!');
}

function gerarPDFRelatorio() {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF('p', 'mm', 'a4');
    desenharCabecalhoPDF(doc, 'RELATÓRIO CONSOLIDADO', 'Resumo de lançamentos filtrados');
    
    const colabFiltro = document.getElementById('rel-colaborador').value;
    const obraFiltro = document.getElementById('rel-obra').value;
    const mesFiltro = document.getElementById('rel-mes').value;
    const statusFiltro = document.getElementById('rel-status').value;

    const dados = lancamentos.filter(l => {
        if (colabFiltro && l.colabId !== colabFiltro) return false;
        if (obraFiltro && l.obraId !== obraFiltro) return false;
        if (mesFiltro && l.mes !== mesFiltro) return false;
        if (statusFiltro && l.status !== statusFiltro) return false;
        return true;
    });

    if (doc.autoTable) {
        doc.autoTable({
            startY: 55,
            head: [['Colaborador', 'Obra', 'Mês', 'Total', 'Status']],
            body: dados.map(l => [l.colab, l.obra, l.mes, formatMoeda(l.total), l.status]),
            headStyles: { fillColor: [15, 23, 42] }
        });
    }
    doc.save('Relatorio_Reembolsos.pdf');
}

